import{_ as e,o as r,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F16: 大股東成本與籌碼結構審計","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6442_光聖/20260504/F16_大股東成本與籌碼結構審計.md","filePath":"審計報告庫/財務審計/6442_光聖/20260504/F16_大股東成本與籌碼結構審計.md"}'),l={name:"審計報告庫/財務審計/6442_光聖/20260504/F16_大股東成本與籌碼結構審計.md"};function i(n,a,h,s,d,_){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="f16-大股東成本與籌碼結構審計" tabindex="-1">F16: 大股東成本與籌碼結構審計 <a class="header-anchor" href="#f16-大股東成本與籌碼結構審計" aria-label="Permalink to &quot;F16: 大股東成本與籌碼結構審計&quot;">​</a></h1><blockquote><p>標的公司：6442 光聖 | 基準日期：20260504</p></blockquote><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</p><h2 id="🎯-專家直斷-40-80-字" tabindex="-1">🎯 專家直斷（40-80 字） <a class="header-anchor" href="#🎯-專家直斷-40-80-字" aria-label="Permalink to &quot;🎯 專家直斷（40-80 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：千張大戶 38-40%、外資 65.4% 籌碼高度集中；董監無質押結構穩健。惟散戶一年暴增 227% 顯示籌碼從集中轉分散，需跟蹤。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：2026/4/30 最新股權分散表</li></ul><h2 id="📊-診斷評級-80-150-字" tabindex="-1">📊 診斷評級（80-150 字） <a class="header-anchor" href="#📊-診斷評級-80-150-字" aria-label="Permalink to &quot;📊 診斷評級（80-150 字）&quot;">​</a></h2><p>最新股權分散（2026/4/30）：千張大戶 11 人持有 38.44%（3,038 萬股），400 張以上合計約 55%。外資持股從 2025 年末 66.83% 降至 65.37%（略減 1.46pp），散戶人數從 2 萬增至 5.2 萬（+160%），籌碼有從大戶流向散戶的跡象。年報中董監事持股合計約 12%（推算），無揭露質押異常。</p><p><strong>評級：A（良）</strong> — 籌碼集中度高但散戶人數近期暴增需注意。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>籌碼集中度：</strong> 千張大戶佔 38-40% 維持穩定，400 張以上合計約 55-58%，核心股東群體未鬆動。但總股東人數從 15,799 人（2025/1）增至 51,716 人（2026/4），+227% 的散戶化速度顯示買盤結構從法人主導轉向散戶追逐，高檔換手風險升溫。</p><p><strong>質押風險：</strong> 年報顯示王姓家族成員及法人代表持股均無質押，董監質押率為 0%。無斷頭風險，大股東財務狀況獨立於股價波動。</p><p><strong>利益綑綁度：</strong> 董監事持股約 12-15%（含法人代表），雖非極高但考量營運權由創始家族掌握，控制權與經營權一致。近一年無內部人大規模申讓紀錄，無異常賣股信號。外資持股約 40-45%，外資動向將顯著影響股價穩定性。</p><h2 id="💡-專家評析-200-450-字" tabindex="-1">💡 專家評析（200-450 字） <a class="header-anchor" href="#💡-專家評析-200-450-字" aria-label="Permalink to &quot;💡 專家評析（200-450 字）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li>散戶人數從 1.5 萬暴增至 5.2 萬（+227%）是籌碼從集中轉分散的典型警訊。千張大戶從 14 人降至 10-11 人、持股從 44.8% 降至 38.4%，頂層主力正在逐步釋出持股。</li><li>在高估值（PE 63 倍）背景下，籌碼鬆動將直接壓抑股價動能。若大戶持續減碼而散戶承接力道不足，股價可能陷入長期盤整或修正。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li>外資持股 65.4% 仍為最強勢的籌碼定錨，只要外資未出現連續性大幅減持，股價下檔風險有限。</li><li>董監零質押且近一年無內部人大規模申讓紀錄，顯示管理層對公司長期價值有信心。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>籌碼結構正從極度集中轉向適度分散，雖非立即危險但需密切跟蹤外資動向與千張大戶數量變化。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>FinMind TaiwanStockShareholdingSpread (backer_holding)</li><li>FinMind TaiwanStockHolding (外資持股)</li><li>年報主要股東名單資料</li><li>數據查詢日期：2026-05-04</li></ul>',23)])])}const p=e(l,[["render",i]]);export{u as __pageData,p as default};
